import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Button,
  DateRangeFilter,
  dispatchAppToast,
  LinListTableConfigModal,
  LinPageLayout,
  loadErpListTableConfig,
  saveErpListTableConfig,
  Select,
  useCatalogTableBusy,
  useErpListSelection,
  type DateRangeValue,
  type ErpListTableConfig,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { VoucherRowActionMenu, type VoucherRowMenuAction } from '../../../components/voucher-list';
import { sxService } from '../../../services/sx/sxService';
import type { ProductionOrderDto } from '../../../services/sx/models';
import { baoCaoThanhPhamDonHangPageLabels as labels } from '../../../constants/baoCaoThanhPhamDonHangPageLabels';
import { formatDateLocal, formatNumber, formatPercent } from '../../../utils/format';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { openListRowMenu } from '../../../utils/openListRowMenu';
import { useMesOrderFinishedReportPermissions } from '../../../hooks/useMesPermissions';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-bao-cao-thanh-pham-don-hang';
const PAGE_ID = 'sx-bao-cao-don-hang';

function monthRangeDefaults() {
  const now = new Date();
  const from = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().slice(0, 10);
  const to = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().slice(0, 10);
  return { from, to };
}

function orderStatusLabel(o: ProductionOrderDto): { label: string; tag: string } {
  const rate = formatPercent(o.completedQty, o.orderQty);
  const end = o.plannedEndDate ? new Date(o.plannedEndDate) : null;
  const late = end && end < new Date() && o.status !== 'Completed' && o.status !== 'Closed';
  if (o.status === 'Completed' || o.status === 'Closed') {
    return { label: labels.statusDone, tag: erp.tagSuccess };
  }
  if (late) return { label: labels.statusLate, tag: erp.tagError };
  return { label: labels.statusInProgress, tag: erp.tagWarning };
}

const BaoCaoThanhPhamDonHangPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const perms = useMesOrderFinishedReportPermissions();
  const defaults = monthRangeDefaults();
  const [fromDate, setFromDate] = useState(defaults.from);
  const [toDate, setToDate] = useState(defaults.to);
  const [status, setStatus] = useState('');
  const [rows, setRows] = useState<ProductionOrderDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [loaded, setLoaded] = useState(false);
  const [configOpen, setConfigOpen] = useState(false);
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: ProductionOrderDto } | null>(
    null,
  );
  const [tableConfig, setTableConfig] = useState<ErpListTableConfig>(() =>
    loadErpListTableConfig(`${TEST_ID}-report-table-config`),
  );
  const { showTableLoading } = useCatalogTableBusy(loading);

  const selection = useErpListSelection({
    rows,
    totalCount: rows.length,
    page: 1,
    pageSize: rows.length || 1,
    getRowId: r => r.id,
  });

  const navigateToLsx = useCallback(
    (id: string) => {
      navigate(`/sx/lsx/${id}`);
    },
    [navigate],
  );

  const handleRowMenuSelect = useCallback(
    (action: VoucherRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      if (action === 'view') navigateToLsx(row.id);
    },
    [rowMenu?.row, navigateToLsx],
  );

  const statusOptions = useMemo(
    () => [
      { value: '', label: labels.statusAll },
      { value: 'Released', label: labels.statusReleased },
      { value: 'Completed', label: labels.statusCompleted },
      { value: 'Closed', label: labels.statusClosed },
    ],
    [],
  );

  const handleLoad = useCallback(() => {
    setLoading(true);
    sxService
      .getProductionOrders({
        status: status || undefined,
        fromDate,
        toDate,
        page: 1,
        pageSize: 200,
      })
      .then(res => {
        setRows(res.items);
        setLoaded(true);
      })
      .catch(err => {
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, labels.loadError),
          type: 'error',
        });
      })
      .finally(() => setLoading(false));
  }, [dispatch, fromDate, status, toDate]);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      if (!cancelled) handleLoad();
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [handleLoad]);

  const handleSaveTableConfig = (next: ErpListTableConfig) => {
    setTableConfig(next);
    saveErpListTableConfig(`${TEST_ID}-report-table-config`, next);
  };

  const done = rows.filter(r => r.status === 'Completed' || r.status === 'Closed').length;
  const late = rows.filter(r => orderStatusLabel(r).label === labels.statusLate).length;
  const avgRate = rows.length
    ? Math.round(rows.reduce((a, r) => a + formatPercent(r.completedQty, r.orderQty), 0) / rows.length)
    : 0;

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-dateRange`,
        content: (
          <div className={erp.field}>
            <DateRangeFilter
              label={labels.dateRangeLabel}
              fullWidth
              testId={`${TEST_ID}-date-range`}
              fromDate={fromDate}
              toDate={toDate}
              onChange={(v: DateRangeValue) => {
                setFromDate(v.fromDate ?? '');
                setToDate(v.toDate ?? '');
              }}
            />
          </div>
        ),
      },
      {
        testId: `${TEST_ID}-field-status`,
        content: (
          <div className={erp.field}>
            <Select
              label={labels.statusLabel}
              value={status}
              onChange={e => setStatus(e.target.value)}
              options={statusOptions}
              size="small"
            />
          </div>
        ),
      },
      {
        testId: `${TEST_ID}-view-btn`,
        content: (
          <Button
            variant="primary"
            onClick={handleLoad}
            loading={loading}
            data-testid={`${TEST_ID}-view-btn`}
          >
            {labels.view}
          </Button>
        ),
      },
    ],
    [fromDate, toDate, status, statusOptions, handleLoad, loading],
  );

  const reportToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: () => {
        if (perms.canRead) handleLoad();
      },
      canChart: perms.canRead && loaded && rows.length > 0,
      onChart: () =>
        dispatchAppToast(dispatch, { message: labels.chartComingSoon, type: 'info' }),
      canPrint: perms.canPrint && loaded && rows.length > 0,
      onPrint: () => window.print(),
      onEditConfig: perms.canConfig ? () => setConfigOpen(true) : undefined,
    }),
    [handleLoad, loaded, rows.length, dispatch, perms],
  );

  const listBody =
    !showTableLoading && rows.length === 0 ? (
      <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
        <i className="fas fa-inbox" />
        <p>{labels.empty}</p>
      </div>
    ) : !showTableLoading ? (
      <div className={erp.tableWrapper}>
        <table className={erp.table} data-testid={`${TEST_ID}-table`}>
          <thead>
            <tr>
              <th>{labels.colCode}</th>
              <th>{labels.colContract}</th>
              <th>{labels.colProduct}</th>
              <th className={erp.colRight}>{labels.colOrderQty}</th>
              <th className={erp.colRight}>{labels.colCompletedQty}</th>
              <th>{labels.colProgress}</th>
              <th>{labels.colDueDate}</th>
              <th>{labels.colStatus}</th>
            </tr>
          </thead>
          <tbody>
            {rows.map(r => {
              const pct = formatPercent(r.completedQty, r.orderQty);
              const st = orderStatusLabel(r);
              return (
                <tr
                  key={r.id}
                  data-testid={`${TEST_ID}-row-${r.id}`}
                  className={
                    selection.activeRow?.id === r.id
                      ? erp.rowSelected
                      : st.label === labels.statusLate
                        ? erp.rowDanger
                        : undefined
                  }
                  onDoubleClick={() => perms.canRead && navigateToLsx(r.id)}
                  onContextMenu={e =>
                    openListRowMenu(e, r, selection.selectActiveRow, setRowMenu)
                  }
                  onClick={e => {
                    if (e.ctrlKey || e.metaKey) {
                      openListRowMenu(e, r, selection.selectActiveRow, setRowMenu);
                    }
                  }}
                >
                  <td>
                    <button
                      type="button"
                      className={erp.codeLink}
                      onClick={() => perms.canRead && navigateToLsx(r.id)}
                    >
                      <code>{r.code}</code>
                    </button>
                  </td>
                  <td>{r.contractCode ?? '—'}</td>
                  <td>{r.productName ?? r.productCode}</td>
                  <td className={erp.colRight}>{formatNumber(r.orderQty)}</td>
                  <td className={erp.colRight}>{formatNumber(r.completedQty)}</td>
                  <td>
                    <div className={erp.progressBar}>
                      <div className={erp.progressFill} style={{ width: `${Math.min(pct, 100)}%` }} />
                    </div>
                    <div className={erp.progressLabel}>{pct}%</div>
                  </td>
                  <td>{formatDateLocal(r.plannedEndDate)}</td>
                  <td>
                    <span className={st.tag}>{st.label}</span>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    ) : null;

  return (
    <div className={erp.voucherListRoot} data-report-list-page data-testid={`${TEST_ID}-list`}>
      <LinPageLayout
        kind="report"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: labels.title,
          subTitle: labels.subtitle,
          titleIconClass: 'fas fa-clipboard-list',
          pageId: PAGE_ID,
        }}
        reportToolbar={reportToolbar}
        listTitle={labels.listTitle}
        listRowMenuHelp
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={8}
        footer={
          loaded && rows.length > 0 ? (
            <div className={erp.paginationRow}>
              <span className={erp.summaryItem}>
                {labels.summaryTotal}: <strong>{rows.length}</strong>
              </span>
              <span className={erp.summaryItem}>
                {labels.summaryDone}: <strong>{done}</strong>
              </span>
              <span className={erp.summaryItem}>
                {labels.summaryLate}: <strong>{late}</strong>
              </span>
              <span className={erp.summaryItem}>
                {labels.summaryAvgProgress}: <strong>{avgRate}%</strong>
              </span>
            </div>
          ) : undefined
        }
        modals={
          <>
            <VoucherRowActionMenu
              open={rowMenu != null}
              x={rowMenu?.x ?? 0}
              y={rowMenu?.y ?? 0}
              onClose={() => setRowMenu(null)}
              onSelect={handleRowMenuSelect}
              testIdPrefix={TEST_ID}
              showView={perms.canRead}
              showEdit={false}
            />
            <LinListTableConfigModal
              isOpen={configOpen}
              onClose={() => setConfigOpen(false)}
              testIdPrefix={TEST_ID}
              config={tableConfig}
              onSave={handleSaveTableConfig}
            />
          </>
        }
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default BaoCaoThanhPhamDonHangPage;
